function isElement(n) {
  return !!n && n.nodeType === 1;
}

function classList(node) {
  return String(node.className || '').split(/\s+/).filter(Boolean);
}

function hasClass(node, cls) {
  return classList(node).includes(cls);
}

function parseStep(step) {
  const s = step.trim();
  if (!s) return null;

  if (s.startsWith('#')) return { kind: 'id', id: s.slice(1) };
  if (s.startsWith('.')) return { kind: 'class', cls: s.slice(1) };

  const parts = s.split('.');
  const tag = parts[0];
  const cls = parts[1];

  if (!tag) return null;
  if (cls) return { kind: 'tagClass', tag, cls };
  return { kind: 'tag', tag: s };
}

function matchesStep(node, stepObj) {
  if (!isElement(node)) return false;

  switch (stepObj.kind) {
    case 'id':
      return String(node.id || '') === stepObj.id;
    case 'class':
      return hasClass(node, stepObj.cls);
    case 'tag':
      return String(node.tagName || '').toLowerCase() === String(stepObj.tag).toLowerCase();
    case 'tagClass':
      return (
        String(node.tagName || '').toLowerCase() === String(stepObj.tag).toLowerCase() &&
        hasClass(node, stepObj.cls)
      );
    default:
      return false;
  }
}

function validateSelector(selector) {
  // keep easy + predictable: reject common unsupported syntax
  // (you can expand later)
  if (/[>+~,:\[\]]/.test(selector)) {
    throw new TypeError('queryAllSimple: unsupported selector syntax');
  }
}

function parseSelector(selector) {
  const parts = String(selector).trim().split(/\s+/).filter(Boolean);
  const steps = parts.map(parseStep);
  if (steps.some((x) => !x)) throw new TypeError('queryAllSimple: invalid selector');

  // reject empty id/class
  for (const st of steps) {
    if (st.kind === 'id' && !st.id) throw new TypeError('queryAllSimple: invalid selector');
    if (st.kind === 'class' && !st.cls) throw new TypeError('queryAllSimple: invalid selector');
    if (st.kind === 'tagClass' && !st.cls) throw new TypeError('queryAllSimple: invalid selector');
  }

  return steps;
}

function matchesChain(node, ancestors, steps) {
  // ancestors excludes node itself; order: root..parent
  const lastIdx = steps.length - 1;
  if (!matchesStep(node, steps[lastIdx])) return false;

  // satisfy earlier steps by scanning ancestors backwards
  let need = lastIdx - 1;
  let i = ancestors.length - 1;

  while (need >= 0) {
    let found = false;
    while (i >= 0) {
      if (matchesStep(ancestors[i], steps[need])) {
        found = true;
        i -= 1;
        break;
      }
      i -= 1;
    }
    if (!found) return false;
    need -= 1;
  }

  return true;
}

function dfs(node, ancestors, visit) {
  if (!node) return;

  if (isElement(node)) {
    visit(node, ancestors);
    ancestors.push(node);
  }

  const children = Array.isArray(node.childNodes) ? node.childNodes : [];
  for (const child of children) {
    dfs(child, ancestors, visit);
  }

  if (isElement(node)) {
    ancestors.pop();
  }
}

export default function queryAllSimple(root, selector) {
  if (!isElement(root)) {
    throw new TypeError('queryAllSimple: root must be an element node');
  }
  if (typeof selector !== 'string' || selector.trim() === '') {
    throw new TypeError('queryAllSimple: selector must be a non-empty string');
  }

  validateSelector(selector);
  const steps = parseSelector(selector);

  const out = [];
  const ancestors = [];

  dfs(root, ancestors, (node, anc) => {
    // anc is the current ancestors stack BEFORE pushing `node`
    if (matchesChain(node, anc, steps)) out.push(node);
  });

  return out;
}
